CREATE PROCEDURE [dbo].[Gnosis_InsertTrackingContainerRequestResponse]
(
	@RequestSent		VARCHAR(MAX),
	@ResponseRcvd	VARCHAR(MAX)
)
 
AS

BEGIN
	
	DECLARE @TrackingContainerKey INT = 0

	INSERT INTO		Gnosis_TrackingContainerRequestResponse
					(RequestSent,ResponseRcvd,CreatedDate)
	SELECT			@RequestSent,@ResponseRcvd,GETDATE()
	SET				@TrackingContainerKey =  @@IDENTITY



	CREATE TABLE #TrackingRequest
	(
		SlNo					INT
		 ,MBL				VARCHAR(50)
		,RequestJSON		NVARCHAR(MAX)

	)


	CREATE TABLE #TrackingRequestDetail
	(
		 MBL					VARCHAR(50)
		,containerNo		VARCHAR(50)
		,OrderDetailKey			INT

	)


	INSERT INTO		#TrackingRequest
					(SlNo,MBL,RequestJSON)
	SELECT			ROW_NUMBER() OVER (ORDER BY MBL), MBL,TrackingRequestJSON
					FROM OPENJSON	(@RequestSent,'$')
									WITH (
										MBL						VARCHAR(50)		'$.submitted_mbl' ,
										TrackingRequestJSON		NVARCHAR(MAX)	'$.containers' AS JSON 
										)
	
	SELECT * FROM #TrackingRequest

	DECLARE @i INT = 1, @n INT = (SELECT COUNT(*) FROM #TrackingRequest), @TrackingRequestJSON NVARCHAR(MAX), @MBL VARCHAR(50)



	WHILE(@i <= @n)
			BEGIN
				SELECT  @TrackingRequestJSON  =  RequestJSON, @MBL = MBL
				FROM #TrackingRequest WHERE SlNo = @i


				INSERT INTO			#TrackingRequestDetail
									(MBL,ContainerNo,OrderDetailKey)
				SELECT				@MBL,ContainerNo,OrderDetailKey
				FROM OPENJSON		(@TrackingRequestJSON,'$')
										WITH (
											ContainerNo				VARCHAR(50)		'$.container_number' ,
											OrderDetailKey			INT				'$.OrderDetailKey'
											)
				SET @i  =  @i + 1
			END

SELECT * FROM #TrackingRequestDetail
	CREATE TABLE #TrackingRespondDetail
	(
		 SlNo						INT
		,TrackingContainerKey		INT
		,MBL						VARCHAR(50)
		,TrackingRequestUUID		VARCHAR(50)
		,TrackingRequestJSON		NVARCHAR(MAX)

	)

	INSERT INTO		#TrackingRespondDetail
					(SLNo,TrackingContainerKey,MBL,TrackingRequestUUID,TrackingRequestJSON)
	SELECT			ROW_NUMBER() OVER (Order By MBL), @TrackingContainerKey,MBL, TrackingrequestUUID, TrackingRequestJSON
					FROM OPENJSON	(@ResponseRcvd,'$')
									WITH (
										MBL						VARCHAR(50)		'$.mbl_number' ,
										TrackingrequestUUID		VARCHAR(50)		'$.tracking_request_uuid',
										TrackingRequestJSON		NVARCHAR(MAX)	'$.container_tracking_requests' AS JSON 
										)
	
	-- SELECT * FROM #TrackingRequestDetail

	DECLARE @TrackingRespondJSON NVARCHAR(MAX),  @TrackingRequestUUID VARCHAR(50)

	SET @i = 1 
	SET @n = (SELECT COUNT(*) FROM #TrackingRespondDetail)

	CREATE TABLE #Gnosis_TrackingContainerRequestResponseDetail
	(		
		TrackingContainerKey		INT	,
		MBL							VARCHAR(50),
		MBLTrackingReqUUID			VARCHAR(50),
		ContainerNo					VARCHAR(50),
		ContainerTrackingReqUUID	VARCHAR(50)

	)

	WHILE(@i <= @n)
		BEGIN
			SELECT  @TrackingRespondJSON  =  TrackingRequestJSON, @MBL = MBL, @TrackingContainerKey = TrackingContainerKey, @TrackingRequestUUID = TrackingRequestUUID
			FROM #TrackingRespondDetail WHERE SlNo = @i


			INSERT INTO			#Gnosis_TrackingContainerRequestResponseDetail
								(TrackingContainerKey,MBL,MBLTrackingReqUUID,ContainerNo,ContainerTrackingReqUUID)
			SELECT				@TrackingContainerKey,@MBL,@TrackingRequestUUID,ContainerNo, TrackingrequestUUID
			FROM OPENJSON		(@TrackingRespondJSON,'$')
									WITH (
										ContainerNo				VARCHAR(50)		'$.container_number' ,
										TrackingrequestUUID		VARCHAR(50)		'$.tracking_request_uuid'
										)
			SET @i  =  @i + 1
		END

	
	INSERT INTO		Gnosis_TrackingContainerRequestResponseDetail
					(TrackingContainerKey,MBL,MBLTrackingReqUUID,ContainerNo,OrderDetailKey,ContainerTrackingReqUUID,CreatedDate)
	SELECT			TrackingContainerKey,A.MBL,MBLTrackingReqUUID,A.ContainerNo,OrderDetailKey,ContainerTrackingReqUUID,GETDATE()
	FROM			#TrackingRequestDetail A
	INNER JOIN		#Gnosis_TrackingContainerRequestResponseDetail B On A.MBL = B.MBL AND A.containerNo = B.ContainerNo 


END
